/**
 * Jira2Markdown Content Script v1.1.0
 * 整合 Modal 編輯器與 ZIP 資源打包功能
 */

(function() {
    console.log("[Jira2Markdown] Advanced version loaded.");

    // --- 功能一：中轉編輯器 (Modal Editor) ---
    function showEditorModal(initialMarkdown, issueInfo) {
        const overlay = document.createElement('div');
        overlay.id = 'j2m-modal-overlay';
        
        overlay.innerHTML = `
            <div id="j2m-modal-container">
                <div id="j2m-modal-header">
                    <h2>Jira2Markdown Editor - ${issueInfo.key}</h2>
                    <span style="color: #6b778c; font-size: 12px;">Editing: ${issueInfo.title}</span>
                </div>
                <div id="j2m-modal-body">
                    <div id="j2m-editor-pane">
                        <div style="margin-bottom: 8px; font-weight: bold; color: #5e6c84;">Markdown Editor</div>
                        <textarea id="j2m-markdown-input">${initialMarkdown}</textarea>
                    </div>
                    <div id="j2m-preview-pane">
                        <div style="margin-bottom: 8px; font-weight: bold; color: #5e6c84;">Live Preview (Basic)</div>
                        <div id="j2m-preview-content"></div>
                        <div id="j2m-attachments-list" style="margin-top: 20px; border-top: 1px solid #ddd; padding-top: 10px;">
                            <div style="font-weight: bold; color: #5e6c84; margin-bottom: 8px;">Attachments to Download:</div>
                            <div id="j2m-attachments-content" style="max-height: 200px; overflow-y: auto; font-size: 12px;"></div>
                        </div>
                    </div>
                </div>
                <div id="j2m-modal-footer">
                    <button id="j2m-btn-cancel" class="j2m-btn j2m-btn-secondary">Cancel</button>
                    <button id="j2m-btn-download-md" class="j2m-btn j2m-btn-secondary">Download Markdown Only</button>
                    <button id="j2m-btn-download-bundle" class="j2m-btn j2m-btn-primary">Download with Attachments</button>
                </div>
            </div>
        `;

        document.body.appendChild(overlay);

        const textarea = overlay.querySelector('#j2m-markdown-input');
        const preview = overlay.querySelector('#j2m-preview-content');
        const attachmentsContent = overlay.querySelector('#j2m-attachments-content');
        const btnCancel = overlay.querySelector('#j2m-btn-cancel');
        const btnDownloadMd = overlay.querySelector('#j2m-btn-download-md');
        const btnDownloadBundle = overlay.querySelector('#j2m-btn-download-bundle');

        // 顯示附件列表
        if (issueInfo.attachments && issueInfo.attachments.length > 0) {
            let attachmentHtml = '';
            issueInfo.attachments.forEach((att, idx) => {
                attachmentHtml += `<div style="padding: 4px; border-bottom: 1px solid #eee;">✓ ${att.name}</div>`;
            });
            attachmentsContent.innerHTML = attachmentHtml;
        } else {
            attachmentsContent.innerHTML = '<div style="color: #999; font-style: italic;">No attachments found</div>';
        }

        // 簡易預覽邏輯 (僅做換行與標題的基本處理，不引入大型 Markdown Parser)
        const updatePreview = () => {
            const text = textarea.value;
            preview.innerHTML = text
                .replace(/^# (.*$)/gim, '<h1>$1</h1>')
                .replace(/^## (.*$)/gim, '<h2>$1</h2>')
                .replace(/^### (.*$)/gim, '<h3>$1</h3>')
                .replace(/\*\*(.*)\*\*/gim, '<b>$1</b>')
                .replace(/\n/g, '<br>');
        };

        textarea.addEventListener('input', updatePreview);
        updatePreview();

        // 關閉Modal的函數
        const closeModal = () => {
            if (document.body.contains(overlay)) {
                document.body.removeChild(overlay);
            }
        };

        // 點擊Cancel按鈕關閉
        btnCancel.onclick = closeModal;
        
        // 點擊overlay背景（外部）關閉
        overlay.onclick = (e) => {
            if (e.target === overlay) {
                closeModal();
            }
        };
        
        // 按ESC鍵關閉
        const handleEsc = (e) => {
            if (e.key === 'Escape') {
                closeModal();
                document.removeEventListener('keydown', handleEsc);
            }
        };
        document.addEventListener('keydown', handleEsc);
        
        btnDownloadMd.onclick = async () => {
            btnDownloadMd.innerText = "Downloading...";
            btnDownloadMd.disabled = true;
            const finalMarkdown = textarea.value;
            await generateZipArchive(finalMarkdown, issueInfo, false);
            closeModal();
        };

        btnDownloadBundle.onclick = async () => {
            btnDownloadBundle.innerText = "Processing Assets...";
            btnDownloadBundle.disabled = true;
            const finalMarkdown = textarea.value;
            await generateZipArchive(finalMarkdown, issueInfo, true);
            closeModal();
        };
    }

    // --- 功能二：提取附件 ---
    async function extractAttachments() {
        const attachments = [];
        
        console.log('[Jira2Markdown] === Starting attachment extraction ===');
        
        // 獲取issue key
        let issueKey = document.querySelector('[data-testid="issue.views.issue-base.foundation.breadcrumbs.breadcrumb-current-issue-container"]')?.innerText.trim() || '';
        issueKey = issueKey.replace(/\s*Export\s+MD\s+Bundle\s*/gi, '').trim();
        
        if (!issueKey) {
            console.log('[Jira2Markdown] Could not find issue key');
            return attachments;
        }
        
        console.log(`[Jira2Markdown] Issue key: ${issueKey}`);
        
        // 策略1: 使用Jira REST API獲取issue信息
        try {
            // 嘗試v2 API (有時v3 API不可用)
            const apiV2Url = `/rest/api/2/issue/${issueKey}`;
            console.log(`[Jira2Markdown] Trying API v2: ${apiV2Url}`);
            
            let response = await fetch(apiV2Url);
            
            // 如果v2失敗，嘗試v3
            if (!response.ok) {
                const apiV3Url = `/rest/api/3/issues/${issueKey}`;
                console.log(`[Jira2Markdown] v2 failed (${response.status}), trying v3: ${apiV3Url}`);
                response = await fetch(apiV3Url);
            }
            
            if (response.ok) {
                const issueData = await response.json();
                console.log('[Jira2Markdown] Issue data retrieved');
                
                // 處理v2和v3的不同結構
                let attachmentArray = [];
                if (issueData.fields && issueData.fields.attachment) {
                    attachmentArray = issueData.fields.attachment;
                } else if (issueData.fields && Array.isArray(issueData.fields.attachment)) {
                    attachmentArray = issueData.fields.attachment;
                }
                
                console.log(`[Jira2Markdown] Found ${attachmentArray.length} attachments from API`);
                
                attachmentArray.forEach((att, idx) => {
                    const fileName = att.filename || `attachment_${att.id}`;
                    const downloadUrl = att.content || att.download || att.url || '';
                    
                    console.log(`[Jira2Markdown] Attachment ${idx}: ${fileName}`);
                    
                    if (downloadUrl) {
                        attachments.push({
                            url: downloadUrl,
                            name: fileName,
                            fileId: att.id,
                            size: att.size
                        });
                    }
                });
            } else {
                console.log(`[Jira2Markdown] API response status: ${response.status}`);
            }
        } catch (apiError) {
            console.error('[Jira2Markdown] Failed to fetch from API:', apiError);
        }
        
        // 策略2: 備選方案 - 如果API失敗，嘗試從DOM提取
        if (attachments.length === 0) {
            console.log('[Jira2Markdown] Trying DOM extraction as fallback');
            
            const filmstripWrapper = document.querySelector('[id="newFileExperienceWrapper"]') || 
                                    document.querySelector('[data-testid*="filmstrip-view"]');
            if (filmstripWrapper) {
                const imgs = filmstripWrapper.querySelectorAll('img');
                console.log(`[Jira2Markdown] Found ${imgs.length} images in filmstrip`);
                
                imgs.forEach((img, idx) => {
                    const src = img.getAttribute('src') || '';
                    const fileId = img.getAttribute('data-fileid') || '';
                    
                    if (fileId) {
                        console.log(`[Jira2Markdown] Image ${idx} has file ID: ${fileId}`);
                        
                        // 清理URL參數，移除預覽參數
                        let downloadUrl = src;
                        if (src.includes('media-cdn.atlassian.com')) {
                            // 移除crop、width、height等預覽參數，保留原始文件URL
                            downloadUrl = src.split('?')[0];  // 只保留問號前的部分
                        }
                        
                        // 嘗試從page text中找到對應的文件名
                        let fileName = `attachment_${fileId}`;
                        const pageText = document.body.innerText;
                        const filePattern = /[\w\-]+\.(png|jpg|jpeg|pdf|doc|docx|xls|xlsx|zip|rar|txt|csv|log|json|xml)/gi;
                        let fileMatch;
                        while ((fileMatch = filePattern.exec(pageText)) !== null) {
                            fileName = fileMatch[0];
                            break;  // 取第一個找到的
                        }
                        
                        console.log(`[Jira2Markdown] Using filename: ${fileName}`);
                        
                        attachments.push({
                            url: downloadUrl,
                            name: fileName,
                            fileId: fileId,
                            originalSrc: src
                        });
                    }
                });
            }
        }
        
        console.log(`[Jira2Markdown] === End attachment extraction ===`);
        console.log(`[Jira2Markdown] Total attachments found: ${attachments.length}`, attachments);
        return attachments;
    }

    // --- 功能三：資源打包下載 (ZIP with Assets) ---
    async function generateZipArchive(markdown, issueInfo, includeAttachments = false) {
        const zip = new JSZip();
        
        // 清理標題 - 確保移除"Export MD Bundle"
        let cleanTitle = issueInfo.title.replace(/Export\s+MD\s+Bundle/gi, '').trim();
        if (!cleanTitle) {
            cleanTitle = 'No Title';
        }
        
        const mdFileName = `${issueInfo.key}_${cleanTitle}.md`;
        
        let updatedMarkdown = markdown;
        const fetchPromises = [];

        if (includeAttachments) {
            const assetsFolder = zip.folder("assets");
            
            // 提取Markdown中的圖片
            const imgRegex = /!\[.*?\]\((https?:\/\/.*?)\)/g;
            let match;
            let assetCount = 0;

            while ((match = imgRegex.exec(markdown)) !== null) {
                const url = match[1];
                const ext = url.split('.').pop().split(/[?#]/)[0] || 'png';
                const fileName = `image_${++assetCount}.${ext}`;
                const relativePath = `./assets/${fileName}`;

                // 替換 Markdown 中的 URL 為相對路徑
                updatedMarkdown = updatedMarkdown.replace(url, relativePath);

                // 非同步抓取資源
                const fetchTask = fetch(url)
                    .then(res => res.blob())
                    .then(blob => {
                        assetsFolder.file(fileName, blob);
                    })
                    .catch(err => console.error(`Failed to fetch asset: ${url}`, err));
                
                fetchPromises.push(fetchTask);
            }

            // 使用保存的附件列表（如果有的話）
            const attachments = issueInfo.attachments || [];
            console.log(`[Jira2Markdown] Processing ${attachments.length} attachments for ZIP`);
            
            attachments.forEach((attachment, index) => {
                const ext = attachment.url.split('.').pop().split(/[?#]/)[0] || 'bin';
                const fileName = `${attachment.name}`;
                
                console.log(`[Jira2Markdown] Fetching attachment: ${attachment.url}`);
                
                // 不使用credentials，以避免CORS問題
                const fetchTask = fetch(attachment.url)
                    .then(res => {
                        console.log(`[Jira2Markdown] Response status for ${attachment.name}: ${res.status}`);
                        if (!res.ok) throw new Error(`HTTP ${res.status}`);
                        return res.blob();
                    })
                    .then(blob => {
                        console.log(`[Jira2Markdown] Successfully fetched ${attachment.name} (${blob.size} bytes)`);
                        assetsFolder.file(fileName, blob);
                    })
                    .catch(err => {
                        console.error(`[Jira2Markdown] Failed to fetch attachment: ${attachment.url}`, err);
                    });
                
                fetchPromises.push(fetchTask);
            });

            // 等待所有資源下載完成
            await Promise.all(fetchPromises);

            // 加入 Markdown 檔案
            zip.file(mdFileName, updatedMarkdown);

            // 生成並下載 ZIP
            const content = await zip.generateAsync({ type: "blob" });
            const zipFileName = `${issueInfo.key}_${cleanTitle}_Bundle.zip`;
            
            console.log(`[Jira2Markdown] Generated ZIP: ${zipFileName}`);
            
            const link = document.createElement("a");
            link.href = URL.createObjectURL(content);
            link.download = zipFileName;
            link.click();
        } else {
            // 純下載 Markdown
            const blob = new Blob([markdown], { type: 'text/markdown' });
            const link = document.createElement("a");
            link.href = URL.createObjectURL(blob);
            link.download = mdFileName;
            link.click();
        }
    }

    let turndownService;
    function initTurndown() {
        if (typeof TurndownService === 'undefined') return false;
        if (turndownService) return true;
        
        turndownService = new TurndownService({
            headingStyle: 'atx',
            codeBlockStyle: 'fenced',
            emDelimiter: '*',
            bulletListMarker: '-',
            preserveEmphasis: true,
            bulletListMarker: '-',
            hr: '---'
        });
        
        // 使用 GFM 插件（自帶完整的表格支持）
        if (typeof turndownPluginGfm !== 'undefined') {
            console.log('[Jira2Markdown] GFM plugin loaded, applying...');
            turndownService.use(turndownPluginGfm.gfm);
        } else {
            console.warn('[Jira2Markdown] GFM plugin not found');
        }
        
        // 手動添加表格轉換規則（備用方案，以防 GFM 不工作）
        turndownService.addRule('table', {
            filter: 'table',
            replacement: function(content) {
                return '\n\n' + content + '\n\n';
            }
        });
        
        turndownService.addRule('table-row', {
            filter: 'tr',
            replacement: function(content, node) {
                var row = '';
                var cells = node.querySelectorAll('th, td');
                
                for (var i = 0; i < cells.length; i++) {
                    var cell = cells[i];
                    var cellText = '';
                    
                    // 直接用 innerText 提取單元格內容
                    cellText = cell.innerText.trim().replace(/\n/g, ' ').replace(/\s+/g, ' ');
                    
                    row += ' ' + cellText + ' |';
                }
                
                // 如果是表頭行，添加分隔線
                if (node.parentNode.tagName === 'THEAD' || node.querySelector('th')) {
                    row += '\n';
                    for (var i = 0; i < cells.length; i++) {
                        row += ' --- |';
                    }
                }
                
                return row + '\n';
            }
        });
        
        turndownService.addRule('table-cell', {
            filter: ['th', 'td'],
            replacement: function(content) {
                return content;
            }
        });
        
        // 改進代碼塊轉換 - 保留格式和換行
        turndownService.addRule('pre', {
            filter: 'pre',
            replacement: function(content, node) {
                var code = node.textContent || '';
                
                // 保留原始的換行和空白
                var lines = code.split('\n');
                var cleanedLines = lines.map(function(line) {
                    return line;  // 保留原始縮進
                });
                
                var cleanedCode = cleanedLines.join('\n').trim();
                
                // 嘗試偵測語言
                var language = '';
                var codeElement = node.querySelector('code');
                if (codeElement && codeElement.className) {
                    var match = codeElement.className.match(/language-(\w+)/);
                    if (match) {
                        language = match[1];
                    }
                }
                
                return '\n```' + language + '\n' + cleanedCode + '\n```\n';
            }
        });
        
        // 改進行內代碼 - 保留原始內容
        turndownService.addRule('code', {
            filter: function(node) {
                return node.tagName === 'CODE' && node.parentNode.tagName !== 'PRE';
            },
            replacement: function(content, node) {
                // 直接使用文本內容，不移除特殊字符
                var text = (node.textContent || '').trim();
                return '`' + text + '`';
            }
        });
        
        // 清理 Jira 特定的 class 和 data 屬性，但保留內容
        turndownService.addRule('cleanup-jira-attrs', {
            filter: function(node) {
                if (node.nodeType !== 1) return false;
                // 只清理有過多 Jira class 的元素，但保留結構
                return node.className && node.className.includes('_');
            },
            replacement: function(content) {
                // 只返回內容，讓 Turndown 用預設規則處理
                return content;
            }
        });
        
        console.log('[Jira2Markdown] Turndown initialized with manual table rules');
        return true;
    }

    // --- 整合流程 ---
    async function handleExport() {
        if (!initTurndown()) return alert("Library loading...");

        try {
            let issueKey = document.querySelector('[data-testid="issue.views.issue-base.foundation.breadcrumbs.breadcrumb-current-issue-container"]')?.innerText.trim() || 'Jira';
            
            // 清理issueKey - 移除可能混入的"Export MD Bundle"
            issueKey = issueKey.replace(/\s*Export\s+MD\s+Bundle\s*/gi, '').trim();
            
            // 提取標題 - 直接從heading元素移除button後再取文本
            let title = 'No Title';
            
            const headingElement = document.querySelector('[data-testid="issue.views.issue-base.foundation.summary.heading"]');
            if (headingElement) {
                // 複製元素，移除所有按鈕後再提取文本
                const clonedElement = headingElement.cloneNode(true);
                
                // 移除所有button及其內容
                clonedElement.querySelectorAll('button').forEach(btn => btn.remove());
                
                // 提取純文本
                title = clonedElement.textContent.trim();
            }
            
            console.log('[Jira2Markdown] Raw title: [' + title + ']');
            
            // 最後雙重確保清理
            title = title.replace(/Export\s+MD\s+Bundle/gi, '')
                        .replace(/Download[^a-zA-Z]*/gi, '')
                        .replace(/\s+/g, ' ')
                        .trim();
            
            if (!title || title.length === 0) {
                title = 'No Title';
            }
            
            console.log('[Jira2Markdown] Extracted - Key: ' + issueKey + ', Clean Title: [' + title + ']');
            
            // 先在這裡提取附件，確保能夠獲取到
            const attachments = await extractAttachments();
            
            // 提取描述 - 支持編輯模式和正常模式
            let initialMarkdown = `# ${title}\n\n`;
            
            // 先診斷 - 打印所有可能的描述容器
            console.log('[Jira2Markdown] === Searching for description containers ===');
            
            // 策略1: 查找normal mode的描述容器
            let descriptionContainer = document.querySelector('[data-testid="issue.views.field.rich-text.description"]');
            console.log('[Jira2Markdown] Normal mode container found:', !!descriptionContainer);
            
            // 策略2: 查找所有contenteditable的元素
            const editables = document.querySelectorAll('[contenteditable="true"]');
            console.log('[Jira2Markdown] Found contenteditable elements:', editables.length);
            editables.forEach((el, idx) => {
                const text = el.innerText?.substring(0, 50) || '';
                console.log(`[Jira2Markdown]   Editable ${idx}: ${text}`);
            });
            
            // 策略3: 查找所有textareas
            const textareas = document.querySelectorAll('textarea');
            console.log('[Jira2Markdown] Found textareas:', textareas.length);
            textareas.forEach((el, idx) => {
                const text = el.value?.substring(0, 50) || '';
                console.log(`[Jira2Markdown]   Textarea ${idx}: ${text}`);
            });
            
            // 策略4: 查找所有包含description的容器
            const allDescContainers = document.querySelectorAll('[data-testid*="description"]');
            console.log('[Jira2Markdown] Found description-related containers:', allDescContainers.length);
            allDescContainers.forEach((el, idx) => {
                const text = el.innerText?.substring(0, 100) || '';
                const html = el.outerHTML?.substring(0, 100) || '';
                console.log(`[Jira2Markdown]   Container ${idx}: data-testid=${el.getAttribute('data-testid')}, text=[${text}]`);
            });
            
            // 實際提取 - 優先嘗試contenteditable (編輯模式)
            let descriptionText = '';
            
            // 先查找contenteditable
            const editableDesc = document.querySelector('[data-testid*="description"] [contenteditable="true"]') ||
                                document.querySelector('[contenteditable="true"]');
            if (editableDesc) {
                descriptionText = editableDesc.innerText || '';
                console.log('[Jira2Markdown] Using contenteditable, length: ' + descriptionText.length);
            }
            
            // 再查找renderer (正常模式)
            if (!descriptionText) {
                descriptionContainer = document.querySelector('[data-testid="issue.views.field.rich-text.description"]');
                if (descriptionContainer) {
                    const renderer = descriptionContainer.querySelector('.ak-renderer-document') || descriptionContainer;
                    const html = renderer.innerHTML || '';
                    console.log('[Jira2Markdown] Using renderer, HTML length: ' + html.length);
                    
                    // 檢查是否有複雜結構（表格或代碼塊）
                    const hasTable = html.includes('<table') || html.includes('<tbody') || html.includes('<tr');
                    const hasCode = html.includes('<pre') || html.includes('<code');
                    console.log('[Jira2Markdown] Has table: ' + hasTable + ', Has code: ' + hasCode);
                    console.log('[Jira2Markdown] Turndown service available: ' + (!!turndownService));
                    
                    if ((hasTable || hasCode) && turndownService) {
                        // 有複雜結構時，優先使用 Turndown 保留格式
                        console.log('[Jira2Markdown] Attempting Turndown for complex structures');
                        try {
                            // 先清理一些 Jira 特定的元素，但保留 emoji 文字表示
                            let cleanedHtml = html;
                            
                            // 用 alt 文字替換 emoji img，而不是完全移除
                            cleanedHtml = cleanedHtml.replace(/<img[^>]*data-emoji[^>]*>/g, function(match) {
                                // 嘗試提取 alt 或 data-emoji-short-name
                                var altMatch = match.match(/alt="([^"]+)"/);
                                var shortNameMatch = match.match(/data-emoji-short-name="([^"]+)"/);
                                var text = altMatch ? altMatch[1] : (shortNameMatch ? shortNameMatch[1] : ':emoji:');
                                return text;
                            });
                            
                            let converted = turndownService.turndown(cleanedHtml);
                            console.log('[Jira2Markdown] Turndown result type: ' + typeof converted + ', length: ' + (converted ? converted.length : 0));
                            
                            // 清理多餘的空白行
                            if (converted) {
                                // 替換 <br> 為實際換行
                                converted = converted.replace(/<br>/g, '');
                                // 移除只有空白的行
                                converted = converted.replace(/\n\s+\n/g, '\n');
                                // 移除多個連續的空白行，只保留單個空白行（段落分隔）
                                converted = converted.replace(/\n\n\n+/g, '');
                                // 移除開頭的多餘空白
                                converted = converted.replace(/^\n+/, '');
                                // 移除結尾的多餘空白
                                converted = converted.replace(/\n+$/, '');
                            }
                            
                            console.log('[Jira2Markdown] After cleanup, length: ' + (converted ? converted.length : 0));
                            console.log('[Jira2Markdown] ===== FULL CONVERTED MARKDOWN =====');
                            console.log(converted);
                            console.log('[Jira2Markdown] ===== END CONVERTED MARKDOWN =====');
                            console.log('[Jira2Markdown] Turndown result (first 100 chars): ' + (converted ? converted.substring(0, 100) : 'null'));
                            
                            // 檢查轉換結果中是否有 HTML table
                            if (converted && converted.includes('<table')) {
                                console.warn('[Jira2Markdown] WARNING: Converted result still contains <table> HTML!');
                                // 尋找表格部分並記錄
                                const tableMatch = converted.match(/<table[^>]*>[\s\S]*?<\/table>/);
                                if (tableMatch) {
                                    console.log('[Jira2Markdown] Table HTML found in result: ' + tableMatch[0].substring(0, 200));
                                }
                            }
                            
                            // 檢查是否有 Markdown 表格格式
                            if (converted && converted.includes('| ---')) {
                                console.log('[Jira2Markdown] ✓ Markdown table format detected');
                            } else if (converted && converted.includes('|')) {
                                console.log('[Jira2Markdown] ✓ Pipe character detected (possible table)');
                            }
                            
                            if (converted && typeof converted === 'string' && converted.trim().length > 0) {
                                descriptionText = converted;
                                console.log('[Jira2Markdown] Turndown conversion successful');
                            } else {
                                // Turndown 失敗時 fallback 到 innerText
                                console.warn('[Jira2Markdown] Turndown returned empty or invalid, using innerText fallback');
                                descriptionText = (renderer.innerText || renderer.textContent || '').trim();
                            }
                        } catch (e) {
                            console.warn('[Jira2Markdown] Turndown conversion error: ' + e.message + ', using innerText fallback');
                            descriptionText = (renderer.innerText || renderer.textContent || '').trim();
                        }
                    } else {
                        // 簡單文本，用 innerText（最快最穩定）
                        descriptionText = (renderer.innerText || renderer.textContent || '').trim();
                        console.log('[Jira2Markdown] Using innerText for simple content, length: ' + descriptionText.length);
                    }
                }
            }
            
            if (descriptionText) {
                initialMarkdown += descriptionText;
            }
            
            console.log('[Jira2Markdown] Final markdown length: ' + initialMarkdown.length);
            console.log('[Jira2Markdown] First 200 chars: ' + initialMarkdown.substring(0, 200));

            // 觸發 Modal 而非直接下載，傳入附件列表
            showEditorModal(initialMarkdown, { key: issueKey, title: title, attachments: attachments });
            
        } catch (error) {
            console.error("[Jira2Markdown] Export error:", error);
        }
    }

    // --- 按鈕注入邏輯 (保留原有邏輯) ---
    function injectButton() {
        if (document.getElementById('jira-to-md-btn')) return;
        const target = document.querySelector('[data-testid="issue-view.views.common.content.main.content-column.top-navigation.actions-bar"]') ||
                     document.querySelector('[data-testid="issue.views.issue-base.foundation.breadcrumbs.breadcrumb-current-issue-container"]');
        if (target) {
            const btn = document.createElement('button');
            btn.id = 'jira-to-md-btn';
            btn.className = 'jira-md-export-button';
            btn.innerHTML = 'Export MD Bundle';
            btn.onclick = handleExport;
            target.appendChild(btn);
        }
    }

    let timeout = null;
    const observer = new MutationObserver(() => {
        if (timeout) clearTimeout(timeout);
        timeout = setTimeout(injectButton, 500);
    });
    observer.observe(document.body, { childList: true, subtree: true });
    setTimeout(injectButton, 1000);
})();
